const expireSeconds = $input.first().json.result.records.SOA[0].expire;
const expireDate = new Date(Date.now() + expireSeconds * 1000);

const day = String(expireDate.getDate()).padStart(2, '0');
const month = String(expireDate.getMonth() + 1).padStart(2, '0'); // Months are 0-indexed
const year = expireDate.getFullYear();

const formatted = `${day}-${month}-${year}`;

return [{ json: { expireDate: formatted } }];
